#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vUv = vUvOriginal ;
float iter = 8*clamp01(uTexSize.z*2048*(0.25+vUv.y));
ret = Get1(vUv); ret1 = ret; ret2 = ret;
for (int n =1; n < iter; n++) {
  ret1 = max(ret1,Get1(vUv+uTexSize.zw*vec2(n,0)));
  ret2 = max(ret2,Get1(vUv+uTexSize.zw*vec2(0,n)));
}

struc = ret1;
mask = clamp01(1-6*lum(struc));
struc *= .1+.04/(length(vRadius/2-length((ret1+ret2*0.2))+0.6));

z = .5/(vUv.y-0.5);
z = min(8,abs(z))*sign(z);
uv2 = vec2 (1*z*(vUv.x-0.5),z);
uv1 = uv2+vec2 (0,0);
noise = texture(sampler_noise_lq,uv1)*mask* min(1,1/(z*z))*0;
uv1 += noise*0.01;
//noise *= 1- (texture(sampler_pw_noise_lq,uv1/vec2 (8,64)));

ret = (pow(1-vRadius,1)/2 + noise*0.4*(z>0))*mask ;;
vRadius = length(uv1.x);
ret += clamp01(0.01/pow(vRadius-.5,2)) * abs(sin(vAngle+q12)) * (mask+0.1) *(GetBlur2(fract(uv1/4-0.1))*6);
ret += struc;

//NEW FLASH
for (int n = 1; n <= 3; n++)
{
  uvt = vec2 (q25,q26) +0.5 * (texture(sampler_noise_lq,n/8+rand_frame)-0.5) + 0.5; ;
  uv3 = vUv - uvt;
  cross = pow(0.00003+abs(uv3.x+uv3.y) *abs(uv3.x-uv3.y),1) * length(uv3);
  flash2 = 1-exp(-q22*0.00002/cross*GetBlur1(uvt) ) ;
//flash2 = 0.01/length(uv3);
  ret += flash2;
}

//ret = GetPixel(vUv);

  fragColor = ret;
}
